import numpy as np

def sigmoid(x): return 1 / (1 + np.exp(-x))
def relu(x): return np.maximum(0, x)
def tanh_fn(x): return np.tanh(x)

x = np.array([-3, -1, 0, 1, 3])
print(f'Input:   {x}')
print(f'Sigmoid: {np.round(sigmoid(x), 3)}')
print(f'ReLU:    {relu(x)}')
print(f'Tanh:    {np.round(tanh_fn(x), 3)}')
